What does the following program print?

```cpp
#include <iostream>

class Base {
public:
    virtual void hello() const { std::cout << "Base\n"; }
};

class Derived : public Base {
public:
    void hello() const { std::cout << "Derived\n"; }
};

void call(const Base& b) { b.hello(); }

int main() {
    Derived d;
    call(d);
}
```

What does this program print?

```cpp
#include <iostream>

class Animal {
public:
    void speak() const { std::cout << "Animal\n"; }
};

class Cat : public Animal {
public:
    void speak() const { std::cout << "Meow\n"; }
};

int main() {
    Cat c;
    Animal* p = &c;
    p->speak();
}
```

